let stats = {
      wins: 0,
      losses: 0
    };

    const audioCtx = new (window.AudioContext || window.webkitAudioContext)();

    function playSound(type) {
      const oscillator = audioCtx.createOscillator();
      const gainNode = audioCtx.createGain();

      oscillator.connect(gainNode);
      gainNode.connect(audioCtx.destination);

      if (type === 'win') {
        oscillator.type = 'sine';
        oscillator.frequency.setValueAtTime(440, audioCtx.currentTime);
        oscillator.frequency.exponentialRampToValueAtTime(880, audioCtx.currentTime + 0.1);
        gainNode.gain.setValueAtTime(0.1, audioCtx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.3);
        oscillator.start();
        oscillator.stop(audioCtx.currentTime + 0.3);
      } else if (type === 'loss') {
        oscillator.type = 'sawtooth';
        oscillator.frequency.setValueAtTime(150, audioCtx.currentTime);
        oscillator.frequency.exponentialRampToValueAtTime(50, audioCtx.currentTime + 0.2);
        gainNode.gain.setValueAtTime(0.05, audioCtx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.4);
        oscillator.start();
        oscillator.stop(audioCtx.currentTime + 0.4);
      } else {
        oscillator.type = 'sine';
        oscillator.frequency.setValueAtTime(600, audioCtx.currentTime);
        gainNode.gain.setValueAtTime(0.05, audioCtx.currentTime);
        gainNode.gain.exponentialRampToValueAtTime(0.01, audioCtx.currentTime + 0.1);
        oscillator.start();
        oscillator.stop(audioCtx.currentTime + 0.1);
      }
    }

    function updateStat(key, delta) {
      stats[key] = Math.max(0, stats[key] + delta);
      document.getElementById(`${key}-val`).innerText = stats[key];

      // Update streak
      const streakText = document.getElementById('streak-text');
      const diff = stats.wins - stats.losses;
      if (diff > 0) {
        streakText.innerHTML = `Session Streak: <span class="text-[#00f5d4]">+${diff} Wins</span>`;
      } else if (diff < 0) {
        streakText.innerHTML = `Session Streak: <span class="text-[#ff4d6d]">${diff} Losses</span>`;
      } else {
        streakText.innerHTML = `Session Streak: <span class="text-white">Neutral</span>`;
      }

      if (delta > 0) {
        playSound(key === 'wins' ? 'win' : 'loss');
        // Add a little pop animation
        const el = document.getElementById(`${key}-val`);
        el.classList.remove('animate-bounce');
        void el.offsetWidth; // trigger reflow
        el.classList.add('animate-bounce');
        setTimeout(() => el.classList.remove('animate-bounce'), 500);
      } else {
        playSound('reset');
      }

      saveStats();
    }

    function resetStats() {
      if (confirm('Reset session stats?')) {
        stats.wins = 0;
        stats.losses = 0;
        document.getElementById('wins-val').innerText = '0';
        document.getElementById('losses-val').innerText = '0';
        document.getElementById('streak-text').innerHTML = `Session Streak: <span class="text-white">Neutral</span>`;
        playSound('reset');
        saveStats();
      }
    }

    function saveStats() {
      localStorage.setItem('marvel_rivals_stats', JSON.stringify(stats));
    }

    function loadStats() {
      const saved = localStorage.getItem('marvel_rivals_stats');
      if (saved) {
        stats = JSON.parse(saved);
        document.getElementById('wins-val').innerText = stats.wins;
        document.getElementById('losses-val').innerText = stats.losses;
        updateStat('wins', 0); // trigger streak update
      }
    }

    // Rank selector (cycle through Marvel Rivals ranks)
    const baseRanks = ["BRONZE", "SILVER", "GOLD", "PLATINUM", "DIAMOND", "GRANDMASTER", "CELESTIAL"];
    const specialRanks = ["ETERNITY", "ONE ABOVE ALL"];

    // Generate full list: Tier III, Tier II, Tier I for base ranks
    const ranks = [];
    baseRanks.forEach(r => {
      ranks.push(`${r} III`);
      ranks.push(`${r} II`);
      ranks.push(`${r} I`);
    });
    ranks.push(...specialRanks);

    const rankColors = {
      "BRONZE": "#cd7f32",
      "SILVER": "#c0c0c0",
      "GOLD": "#ffd700",
      "PLATINUM": "#a5f3fc",
      "DIAMOND": "#3b82f6",
      "GRANDMASTER": "#7e22ce",
      "CELESTIAL": "#f97316",
      "ETERNITY": "#d8b4fe",
      "ONE ABOVE ALL": "#ef4444"
    };

    let currentRankIndex = 11; // Default to Platinum I
    function updateRank(delta) {
      currentRankIndex = (currentRankIndex + delta + ranks.length) % ranks.length;
      const rankName = ranks[currentRankIndex];
      const display = document.getElementById('rank-display');
      display.innerText = rankName;

      // Extract base rank for color
      const base = Object.keys(rankColors).find(b => rankName.startsWith(b));
      if (base) {
        display.style.color = rankColors[base];
        display.style.borderColor = `${rankColors[base]}33`; // 20% opacity border
        display.style.textShadow = `0 0 10px ${rankColors[base]}44`;
      }

      if (delta !== 0) playSound('reset');
      localStorage.setItem('marvel_rivals_rank', rankName);
    }

    const savedRank = localStorage.getItem('marvel_rivals_rank');
    if (savedRank) {
      currentRankIndex = ranks.indexOf(savedRank);
      if (currentRankIndex === -1) currentRankIndex = 11; 
    }
    updateRank(0); // Initialize colors

    loadStats();

    // Initial Firehose setup (optional: react to chat if streamer wants to use !win / !loss)
    const firehose = new Firehose();
    firehose.on("chat", (msg) => {
      // Only streamer or mods can update
      if (msg.sender.roles.includes('BROADCASTER') || msg.sender.roles.includes('MODERATOR')) {
        if (msg.raw.toLowerCase() === '!win') updateStat('wins', 1);
        if (msg.raw.toLowerCase() === '!loss') updateStat('losses', 1);
        if (msg.raw.toLowerCase() === '!reset') {
            stats.wins = 0;
            stats.losses = 0;
            updateStat('wins', 0);
            updateStat('losses', 0);
        }
      }
    });
